class BlobProcessor:
    """Handles reading and processing files from Azure Blob Storage."""

    def __init__(self, credential):
        self.blob_service_client = BlobServiceClient(
            account_url=STORAGE_ACCOUNT_URL,
            credential=credential
        )
        self.container_client = self.blob_service_client.get_container_client(
            STORAGE_CONTAINER_NAME
        )

    def read_blob(self, blob_name: str) -> bytes:
        """Read a blob's content from storage."""
        blob_client = self.container_client.get_blob_client(blob_name)
        blob_data = blob_client.download_blob()
        return blob_data.readall()

    def process_file(self, blob_name: str, content: bytes) -> Dict[str, Any]:
        """
        Process file content and return structured results.
        Customize this method based on your specific processing needs.
        """
        content_str = content.decode("utf-8", errors="replace")

        # Example processing: extract metadata and basic stats
        lines = content_str.split("\n")
        word_count = sum(len(line.split()) for line in lines)

        result = {
            "id": blob_name.replace("/", "_").replace(".", "_"),
            "source_blob": blob_name,
            "file_size_bytes": len(content),
            "line_count": len(lines),
            "word_count": word_count,
            "processed_at": datetime.datetime.utcnow().isoformat(),
            "status": "processed",
            "content_preview": content_str[:500] if content_str else "",
            "partition_key": blob_name.split("/")[0] if "/" in blob_name else "default"
        }

        return result

    def mark_blob_processed(self, blob_name: str):
        """Set metadata on blob to indicate it has been processed."""
        blob_client = self.container_client.get_blob_client(blob_name)
        blob_client.set_blob_metadata(
            metadata={
                "processed": "true",
                "processed_at": datetime.datetime.utcnow().isoformat()
            }
        )


class CosmosDBWriter:
    """Handles writing processing results to Cosmos DB."""

    def __init__(self, credential):
        self.client = CosmosClient(
            url=COSMOS_ENDPOINT,
            credential=credential
        )
        self.database = self.client.get_database_client(COSMOS_DATABASE_NAME)
        self.container = self.database.get_container_client(COSMOS_CONTAINER_NAME)

    def ensure_database_and_container(self):
        """
        Create database and container if they don't exist.
        NOTE: This requires 'Cosmos DB Account Contributor' role.
        In production, provision infrastructure via IaC (Terraform/Bicep) and
        use 'Cosmos DB Built-in Data Contributor' for data plane operations only.
        """
        try:
            self.client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
            database = self.client.get_database_client(COSMOS_DATABASE_NAME)
            database.create_container_if_not_exists(
                id=COSMOS_CONTAINER_NAME,
                partition_key=PartitionKey(path="/partition_key"),
                offer_throughput=400
            )
            logging.info("Database and container ensured.")
        except Exception as e:
            logging.warning(f"Could not ensure database/container (may already exist): {e}")

    def write_result(self, result: Dict[str, Any]) -> Dict[str, Any]:
        """Write a processing result to Cosmos DB."""
        response = self.container.upsert_item(body=result)
        logging.info(f"Written result to Cosmos DB: {result['id']}")
        return response

    def write_results_batch(self, results: list) -> list:
        """Write multiple results to Cosmos DB."""
        responses = []
        for result in results:
            response = self.write_result(result)
            responses.append(response)
        return responses


class EventGridNotifier:
    """Handles sending notifications via Azure Event Grid."""

    def __init__(self, credential):
        self.client = EventGridPublisherClient(
            endpoint=EVENTGRID_TOPIC_ENDPOINT,
            credential=credential
        )

    def send_processing_complete_event(
        self,
        blob_name: str,
        result: Dict[str, Any],
        success: bool = True
    ):
        """Send an event notification when file processing is complete."""
        event = CloudEvent(
            type="FileProcessing.Complete" if success else "FileProcessing.Failed",
            source=f"/azure/functions/file-processor",
            data={
                "blob_name": blob_name,
                "result_id": result.get("id", "unknown"),
                "status": result.get("status", "unknown"),
                "processed_at": result.get("processed_at", ""),
                "file_size_bytes": result.get("file_size_bytes", 0),
                "word_count": result.get("word_count", 0),
                "success": success
            },
            subject=f"files/{blob_name}"
        )

        self.client.send([event])
        logging.info(f"Event Grid notification sent for: {blob_name}")

    def send_error_event(self, blob_name: str, error_message: str):
        """Send an error event when processing fails."""
        event = CloudEvent(
            type="FileProcessing.Error",
            source="/azure/functions/file-processor",
            data={
                "blob_name": blob_name,
                "error": error_message,
                "timestamp": datetime.datetime.utcnow().isoformat()
            },
            subject=f"files/{blob_name}/error"
        )

        self.client.send([event])
        logging.warning(f"Error event sent for: {blob_name}")


def process_single_blob(
    blob_name: str,
    blob_processor: BlobProcessor,
    cosmos_writer: CosmosDBWriter,
    notifier: EventGridNotifier
) -> Dict[str, Any]:
    """Process a single blob end-to-end: read, process, store, notify."""
    logging.info(f"Processing blob: {blob_name}")

    try:
        # Step 1: Read blob from storage
        content = blob_processor.read_blob(blob_name)
        logging.info(f"Read {len(content)} bytes from {blob_name}")

        # Step 2: Process the file content
        result = blob_processor.process_file(blob_name, content)
        logging.info(f"Processed {blob_name}: {result['word_count']} words, {result['line_count']} lines")

        # Step 3: Write results to Cosmos DB
        cosmos_writer.write_result(result)
        logging.info(f"Stored result in Cosmos DB: {result['id']}")

        # Step 4: Mark blob as processed
        try:
            blob_processor.mark_blob_processed(blob_name)
        except Exception as e:
            logging.warning(f"Could not mark blob as processed: {e}")

        # Step 5: Send success notification via Event Grid
        try:
            notifier.send_processing_complete_event(blob_name, result, success=True)
        except Exception as e:
            logging.warning(f"Could not send Event Grid notification: {e}")

        return result

    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {str(e)}")

        error_result = {
            "id": blob_name.replace("/", "_").replace(".", "_"),
            "source_blob": blob_name,
            "status": "failed",
            "error": str(e),
            "processed_at": datetime.datetime.utcnow().isoformat(),
            "partition_key": blob_name.split("/")[0] if "/" in blob_name else "default"
        }

        # Try to store the error in Cosmos DB
        try:
            cosmos_writer.write_result(error_result)
        except Exception as cosmos_err:
            logging.error(f"Could not write error to Cosmos DB: {cosmos_err}")

        # Try to send error notification
        try:
            notifier.send_error_event(blob_name, str(e))
        except Exception as eg_err:
            logging.error(f"Could not send error event: {eg_err}")

        raise


