@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to manually process a specific blob or batch of blobs.
    
    Request body:
    {
        "blob_name": "path/to/file.txt"
    }
    or
    {
        "blob_names": ["file1.txt", "file2.txt"]
    }
    or
    {
        "process_all": true
    }
    """
    logging.info("HTTP trigger: Process request received")

    try:
        req_body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON in request body"}),
            status_code=400,
            mimetype="application/json"
        )

    credential = get_credential()
    blob_processor = BlobProcessor(credential)
    cosmos_writer = CosmosDBWriter(credential)
    notifier = EventGridNotifier(credential)

    # Ensure Cosmos DB infrastructure exists
    cosmos_writer.ensure_database_and_container()

    results = []
    errors = []

    if "blob_name" in req_body:
        # Process a single blob
        blob_names = [req_body["blob_name"]]
    elif "blob_names" in req_body:
        # Process multiple blobs
        blob_names = req_body["blob_names"]
    elif req_body.get("process_all", False):
        # Process all blobs in the container
        blob_names = [
            blob.name
            for blob in blob_processor.container_client.list_blobs()
            if not (blob.metadata and blob.metadata.get("processed") == "true")
        ]
    else:
        return func.HttpResponse(
            json.dumps({
                "error": "Request must include 'blob_name', 'blob_names', or 'process_all'"
            }),
            status_code=400,
            mimetype="application/json"
        )

    for blob_name in blob_names:
        try:
            result = process_single_blob(
                blob_name, blob_processor, cosmos_writer, notifier
            )
            results.append({
                "blob_name": blob_name,
                "status": "success",
                "result_id": result["id"]
            })
        except Exception as e:
            errors.append({
                "blob_name": blob_name,
                "status": "error",
                "error": str(e)
            })

    response_body = {
        "total_processed": len(results),
        "total_errors": len(errors),
        "results": results,
        "errors": errors
    }

    status_code = 200 if not errors else 207  # 207 Multi-Status if partial failures
    return func.HttpResponse(
        json.dumps(response_body, indent=2),
        status_code=status_code,
        mimetype="application/json"
    )


